const exec = $json.execution;
const wf = $json.workflow;
const err = exec.error;

const timestamp = new Date().toLocaleString('cs-CZ', { timeZone: 'Europe/Prague' });

// Try to extract client name from workflow name (convention: "[ClientName] — WorkflowType")
const wfName = wf.name || 'Neznámý workflow';
const clientMatch = wfName.match(/^(.+?)\s*[—\-]/);
const clientName = clientMatch ? clientMatch[1].trim() : wfName;

const subject = `⚠️ Chyba: ${wfName}`;

const htmlBody = `
<div style="font-family:sans-serif;max-width:600px">
  <h2 style="color:#dc2626">⚠️ Chyba ve workflow</h2>
  <table style="border-collapse:collapse;width:100%">
    <tr><td style="padding:6px 0;font-weight:bold;width:160px">Klient</td><td style="padding:6px 0">${clientName}</td></tr>
    <tr><td style="padding:6px 0;font-weight:bold">Workflow</td><td style="padding:6px 0">${wfName}</td></tr>
    <tr><td style="padding:6px 0;font-weight:bold">Chyba</td><td style="padding:6px 0;color:#dc2626">${err?.message || 'Neznámá chyba'}</td></tr>
    <tr><td style="padding:6px 0;font-weight:bold">Poslední uzel</td><td style="padding:6px 0">${exec.lastNodeExecuted || '—'}</td></tr>
    <tr><td style="padding:6px 0;font-weight:bold">Čas</td><td style="padding:6px 0">${timestamp}</td></tr>
    <tr><td style="padding:6px 0;font-weight:bold">Execution ID</td><td style="padding:6px 0">${exec.id || '—'}</td></tr>
  </table>
  ${exec.url ? `<p style="margin-top:16px"><a href="${exec.url}" style="background:#2563eb;color:#fff;padding:10px 20px;border-radius:6px;text-decoration:none;font-weight:bold">Zobrazit execution →</a></p>` : ''}
  ${err?.stack ? `<details style="margin-top:16px"><summary style="cursor:pointer;color:#6b7280">Stack trace</summary><pre style="background:#f3f4f6;padding:12px;border-radius:6px;font-size:12px;overflow:auto">${err.stack}</pre></details>` : ''}
</div>
`;

return [{ json: { subject, htmlBody, clientName, wfName, errorMessage: err?.message } }];
